// replace URL if it matches
function overrideURL(url) {
    for (const original in overrides) {
        if (url.includes(original)) {
            return overrides[original];
        }
    }
    return url;
}

/* IMG src property override */

const imgSrc = Object.getOwnPropertyDescriptor(
    HTMLImageElement.prototype,
    "src"
);

Object.defineProperty(HTMLImageElement.prototype, "src", {
    set(value) {
        return imgSrc.set.call(this, overrideURL(value));
    },
    get() {
        return imgSrc.get.call(this);
    }
});

/* setAttribute override */

const origSetAttr = Element.prototype.setAttribute;

Element.prototype.setAttribute = function(name, value) {
    if (name === "src") {
        value = overrideURL(value);
    }
    return origSetAttr.call(this, name, value);
};

/* CSS background-image override */

const origSetProp = CSSStyleDeclaration.prototype.setProperty;

CSSStyleDeclaration.prototype.setProperty = function(name, value) {
    if (value && value.includes("url(")) {
        for (const original in overrides) {
            if (value.includes(original)) {
                value = `url("${overrides[original]}")`;
            }
        }
    }
    return origSetProp.call(this, name, value);
};

